svg.script:
var fs = document.querySelectorAll("[data-frame]");
  var n = fs.length;
  var cur = 0;
  fs[0].style.opacity = "1";
  if (!window.matchMedia("(prefers-reduced-motion: reduce)").matches) {
    setInterval(function() {
      fs[cur].style.opacity = "0";
      cur = (cur + 1) % n;
      fs[cur].style.opacity = "1";
    }, 42);
  }
